use std::fs;
use std::path::Path;

use tansu2::api_types::*;
use ts_rs::TS;

fn main() {
    let check = std::env::args().any(|arg| arg == "--check");
    let mut output = String::from(
        "// Generated by cargo run --bin gen-api-types. Do not edit.\n/* oxlint-disable typescript-eslint/array-type */\n\n",
    );
    push::<VaultEntry>(&mut output);
    push::<NoteMeta>(&mut output);
    push::<NoteDocument>(&mut output);
    push::<RevisionMeta>(&mut output);
    push::<RevisionDocument>(&mut output);
    push::<NoteEventKind>(&mut output);
    push::<NoteEventSource>(&mut output);
    push::<ConflictDraftMeta>(&mut output);
    push::<ConflictDraftDocument>(&mut output);
    push::<Settings>(&mut output);
    push::<SessionState>(&mut output);
    push::<SessionTab>(&mut output);
    push::<SearchStatus>(&mut output);
    push::<SearchHit>(&mut output);
    push::<BootstrapResponse>(&mut output);
    push::<ServerEvent>(&mut output);
    push::<ServerEventKind>(&mut output);
    push::<CreateNoteRequest>(&mut output);
    push::<SaveNoteRequest>(&mut output);
    push::<RenameNoteRequest>(&mut output);
    push::<NoteMutationResponse>(&mut output);
    push::<ImageUploadResponse>(&mut output);
    push::<ApiErrorResponse>(&mut output);
    push::<ApiErrorKind>(&mut output);
    push::<PathValidationReason>(&mut output);
    push::<UnresolvedReason>(&mut output);

    let path = Path::new("web/ts/types.generated.ts");
    if check {
        let current = fs::read_to_string(path).unwrap_or_default();
        if current != output {
            eprintln!("generated API types are stale");
            std::process::exit(1);
        }
    } else {
        fs::create_dir_all(path.parent().expect("generated type parent")).unwrap();
        fs::write(path, output).unwrap();
    }
}

fn push<T: TS>(output: &mut String) {
    let decl = T::decl(&ts_rs::Config::default());
    output.push_str(&decl.replacen("type ", "export type ", 1));
    output.push_str("\n\n");
}
